class PaymentCardManager(private val context: Context) {
    
    private val securityManager = PaymentSecurityManager(context)
    private val gson = Gson()
    private val CARDS_KEY = "saved_cards"
    
    fun saveCard(card: PaymentCard): Boolean {
        return try {
            val cards = getSavedCards().toMutableList()
            val cardJson = gson.toJson(card)
            val encryptedCard = securityManager.encryptCardData(cardJson)
            
            cards.add(encryptedCard)
            
            val cardsJson = gson.toJson(cards)
            securityManager.saveSecureData(CARDS_KEY, cardsJson)
            true
        } catch (e: Exception) {
            Log.e("PaymentCardManager", "Failed to save card", e)
            false
        }
    }
    
    fun getSavedCards(): List<PaymentCard> {
        return try {
            val cardsJson = securityManager.getSecureData(CARDS_KEY) ?: return emptyList()
            val encryptedCards: List<String> = gson.fromJson(cardsJson, object : TypeToken<List<String>>() {}.type)
            
            encryptedCards.mapNotNull { encryptedCard ->
                try {
                    val cardJson = securityManager.decryptCardData(encryptedCard)
                    gson.fromJson(cardJson, PaymentCard::class.java)
                } catch (e: Exception) {
                    Log.e("PaymentCardManager", "Failed to decrypt card", e)
                    null
                }
            }
        } catch (e: Exception) {
            Log.e("PaymentCardManager", "Failed to get saved cards", e)
            emptyList()
        }
    }
    
    fun deleteCard(cardNumber: String): Boolean {
        return try {
            val cards = getSavedCards().toMutableList()
            cards.removeAll { it.cardNumber == cardNumber }
            
            val encryptedCards = cards.map { card ->
                val cardJson = gson.toJson(card)
                securityManager.encryptCardData(cardJson)
            }
            
            val cardsJson = gson.toJson(encryptedCards)
            securityManager.saveSecureData(CARDS_KEY, cardsJson)
            true
        } catch (e: Exception) {
            Log.e("PaymentCardManager", "Failed to delete card", e)
            false
        }
    }
    
    fun validateCard(card: PaymentCard): Boolean {
        if (!validateCardNumber(card.cardNumber)) return false
        if (!validateExpiryDate(card.expiryMonth, card.expiryYear)) return false
        if (!validateCVV(card.cvv, card.cardType)) return false
        return true
    }
    
    private fun validateCardNumber(cardNumber: String): Boolean {
        val digits = cardNumber.replace("\\s".toRegex(), "")
        if (digits.length < 13 || digits.length > 19) return false
        
        var sum = 0
        var alternate = false
        for (i in digits.length - 1 downTo 0) {
            var n = digits[i].toString().toInt()
            if (alternate) {
                n *= 2
                if (n > 9) n -= 9
            }
            sum += n
            alternate = !alternate
        }
        return sum % 10 == 0
    }
    
    private fun validateExpiryDate(month: Int, year: Int): Boolean {
        if (month < 1 || month > 12) return false
        
        val calendar = Calendar.getInstance()
        val currentYear = calendar.get(Calendar.YEAR)
        val currentMonth = calendar.get(Calendar.MONTH) + 1
        
        if (year < currentYear) return false
        if (year == currentYear && month < currentMonth) return false
        
        return true
    }
    
    private fun validateCVV(cvv: String, cardType: CardType): Boolean {
        val expectedLength = if (cardType == CardType.AMEX) 4 else 3
        return cvv.length == expectedLength && cvv.all { it.isDigit() }
    }
    
    fun detectCardType(cardNumber: String): CardType {
        val digits = cardNumber.replace("\\s".toRegex(), "")
        return when {
            digits.matches("^4[0-9]{12}(?:[0-9]{3})?$".toRegex()) -> CardType.VISA
            digits.matches("^5[1-5][0-9]{14}$".toRegex()) -> CardType.MASTERCARD
            digits.matches("^3[47][0-9]{13}$".toRegex()) -> CardType.AMEX
            digits.matches("^6(?:011|5[0-9]{2})[0-9]{12}$".toRegex()) -> CardType.DISCOVER
            else -> CardType.UNKNOWN
        }
    }
}

